class _RequestHistoryTimeline extends StatelessWidget {
  const _RequestHistoryTimeline({
    required this.contactId,
    required this.requests,
  });

  final String contactId;
  final List<ContactRequestModel> requests;

  @override
  Widget build(BuildContext context) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: requests
          .map(
            (request) => Padding(
              padding: const EdgeInsets.only(bottom: 8),
              child: _RequestHistoryThread(
                contactId: contactId,
                request: request,
              ),
            ),
          )
          .toList(),
    );
  }
}

class _RequestHistoryThread extends StatefulWidget {
  const _RequestHistoryThread({required this.contactId, required this.request});

  final String contactId;
  final ContactRequestModel request;

  @override
  State<_RequestHistoryThread> createState() => _RequestHistoryThreadState();
}

class _RequestHistoryThreadState extends State<_RequestHistoryThread> {
  final controller = Get.find<CustomersController>();
  bool _loaded = false;

  String get _matchKey => '${widget.contactId}:${widget.request.id}';

  @override
  void initState() {
    super.initState();
    _loadMatches();
  }

  void _loadMatches() {
    if (_loaded || widget.request.id.isEmpty) return;
    _loaded = true;
    controller.loadRequestMatches(widget.contactId, widget.request.id);
  }

  @override
  Widget build(BuildContext context) {
    final request = widget.request;
    final entries = request.history.toList()
      ..sort((a, b) {
        final left = a.changedAt ?? DateTime.fromMillisecondsSinceEpoch(0);
        final right = b.changedAt ?? DateTime.fromMillisecondsSinceEpoch(0);
        return right.compareTo(left);
      });
    final latestText = entries.isEmpty
        ? 'Ã™â€¡Ã™â€ Ã™Ë†Ã˜Â² Ã˜ÂªÃ˜Â§Ã˜Â±Ã›Å’Ã˜Â®Ãšâ€ Ã™â€¡Ã¢â‚¬Å’Ã˜Â§Ã›Å’ Ã˜Â¨Ã˜Â±Ã˜Â§Ã›Å’ Ã˜Â§Ã›Å’Ã™â€  Ã˜Â¯Ã˜Â±Ã˜Â®Ã™Ë†Ã˜Â§Ã˜Â³Ã˜Âª Ã˜Â«Ã˜Â¨Ã˜Âª Ã™â€ Ã˜Â´Ã˜Â¯Ã™â€¡ Ã˜Â§Ã˜Â³Ã˜Âª.'
        : entries.first.description;
    final scheme = Theme.of(context).colorScheme;
    return DecoratedBox(
      decoration: BoxDecoration(
        color: scheme.surfaceContainerHighest.withValues(alpha: 0.28),
        borderRadius: BorderRadius.circular(8),
        border: Border.all(
          color: scheme.outlineVariant.withValues(alpha: 0.45),
        ),
      ),
      child: Theme(
        data: Theme.of(context).copyWith(dividerColor: Colors.transparent),
        child: ExpansionTile(
          onExpansionChanged: (expanded) {
            if (expanded) _loadMatches();
          },
          tilePadding: const EdgeInsets.symmetric(horizontal: 10),
          childrenPadding: const EdgeInsets.fromLTRB(10, 0, 10, 10),
          leading: const Icon(Icons.campaign_outlined),
          title: Row(
            children: [
              Expanded(
                child: Text(
                  request.title,
                  style: const TextStyle(fontWeight: FontWeight.w900),
                  overflow: TextOverflow.ellipsis,
                ),
              ),
              _StatusPill(status: request.status),
            ],
          ),
          subtitle: Text(
            latestText,
            maxLines: 1,
            overflow: TextOverflow.ellipsis,
          ),
          children: [
            _RequestMatchesPanel(matchKey: _matchKey),
            const SizedBox(height: 10),
            if (entries.isEmpty)
              const Align(
                alignment: Alignment.centerRight,
                child: Padding(
                  padding: EdgeInsets.all(10),
                  child: Text(
                    'Ã˜Â§Ã›Å’Ã™â€  ÃšÂ©Ã˜Â§Ã™â€ Ã˜Â§Ã™â€ž Ã™â€¡Ã™â€ Ã™Ë†Ã˜Â² Ã™Â¾Ã›Å’Ã˜Â§Ã™â€¦Ã›Å’ Ã™â€ Ã˜Â¯Ã˜Â§Ã˜Â±Ã˜Â¯.',
                  ),
                ),
              )
            else
              ...entries.map((entry) => _HistoryMessageBubble(entry: entry)),
          ],
        ),
      ),
    );
  }
}

class _HistoryMessageBubble extends StatelessWidget {
  const _HistoryMessageBubble({required this.entry});

  final ContactRequestHistoryEntryModel entry;

  @override
  Widget build(BuildContext context) {
    final scheme = Theme.of(context).colorScheme;
    return Align(
      alignment: Alignment.centerRight,
      child: ConstrainedBox(
        constraints: const BoxConstraints(maxWidth: 620),
        child: Container(
          margin: const EdgeInsets.only(bottom: 8, left: 26),
          padding: const EdgeInsets.fromLTRB(12, 10, 12, 8),
          decoration: BoxDecoration(
            color: scheme.primaryContainer.withValues(alpha: 0.42),
            borderRadius: const BorderRadius.only(
              topLeft: Radius.circular(8),
              topRight: Radius.circular(8),
              bottomLeft: Radius.circular(8),
              bottomRight: Radius.circular(2),
            ),
            border: Border.all(color: scheme.primary.withValues(alpha: 0.20)),
          ),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                entry.description,
                style: const TextStyle(fontWeight: FontWeight.w800),
              ),
              if (entry.changes.isNotEmpty) ...[
                const SizedBox(height: 8),
                Wrap(
                  spacing: 6,
                  runSpacing: 6,
                  children: entry.changes
                      .map(
                        (change) => Chip(
                          visualDensity: VisualDensity.compact,
                          label: Text(_historyChangeText(change)),
                        ),
                      )
                      .toList(),
                ),
              ],
              const SizedBox(height: 6),
              Row(
                mainAxisSize: MainAxisSize.min,
                children: [
                  Icon(
                    Icons.schedule_rounded,
                    size: 14,
                    color: scheme.onSurfaceVariant,
                  ),
                  const SizedBox(width: 4),
                  Text(
                    _formatPreciseDate(entry.changedAt),
                    style: Theme.of(context).textTheme.bodySmall?.copyWith(
                      color: scheme.onSurfaceVariant,
                    ),
                  ),
                ],
              ),
            ],
          ),
        ),
      ),
    );
  }
}

class _RequestMatchesPanel extends StatelessWidget {
  const _RequestMatchesPanel({required this.matchKey});

  final String matchKey;

  @override
  Widget build(BuildContext context) {
    final controller = Get.find<CustomersController>();
    return Obx(() {
      final loading = controller.loadingMatches.contains(matchKey);
      final matches = controller.requestMatches[matchKey] ?? const [];
      if (loading && matches.isEmpty) {
        return const Padding(
          padding: EdgeInsets.all(12),
          child: Center(child: CircularProgressIndicator()),
        );
      }
      if (matches.isEmpty) {
        return const _EmptyMatchesBox();
      }
      return Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          const Padding(
            padding: EdgeInsets.only(bottom: 8),
            child: Text(
              'Ã™ÂÃ˜Â§Ã›Å’Ã™â€žÃ¢â‚¬Å’Ã™â€¡Ã˜Â§Ã›Å’ Ã™Â¾Ã›Å’Ã˜Â´Ã™â€ Ã™â€¡Ã˜Â§Ã˜Â¯Ã›Å’',
              style: TextStyle(fontWeight: FontWeight.w900),
            ),
          ),
          ...matches.map((match) => _MatchCard(match: match)),
        ],
      );
    });
  }
}

