class ContactCreatePage extends StatefulWidget {
  const ContactCreatePage({super.key, this.initial});

  final ContactModel? initial;

  @override
  State<ContactCreatePage> createState() => _ContactCreatePageState();
}

class _ContactCreatePageState extends State<ContactCreatePage> {
  final controller = Get.find<CustomersController>();
  final formKey = GlobalKey<FormState>();
  final firstName = TextEditingController();
  final lastName = TextEditingController();
  final company = TextEditingController();
  final note = TextEditingController();
  final phones = <_PhoneDraft>[].obs;
  final selectedTags = <String>[].obs;
  final customTag = TextEditingController();
  final properties = <_PropertyDraft>[].obs;
  final requests = <_RequestDraft>[].obs;

  @override
  void initState() {
    super.initState();
    final initial = widget.initial;
    if (initial == null) {
      phones.add(_PhoneDraft());
    } else {
      firstName.text = initial.firstName;
      lastName.text = initial.lastName;
      company.text = initial.company;
      note.text = initial.note;
      phones.assignAll(initial.phones.map(_PhoneDraft.fromModel));
      if (phones.isEmpty) phones.add(_PhoneDraft());
      selectedTags.assignAll(initial.tags);
      properties.assignAll(initial.properties.map(_PropertyDraft.fromModel));
      requests.assignAll(initial.requests.map(_RequestDraft.fromModel));
    }
    controller.loadTags();
  }

  @override
  void dispose() {
    firstName.dispose();
    lastName.dispose();
    company.dispose();
    note.dispose();
    customTag.dispose();
    for (final item in phones) {
      item.dispose();
    }
    for (final item in properties) {
      item.dispose();
    }
    for (final item in requests) {
      item.dispose();
    }
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return PanelScaffold(
      title: const Text(
